#include<bits/stdc++.h>
using namespace std;
typedef unsigned long long ull;
ull h1[500010],h2[500010],b[500010];
char s1[500010],s2[500010];
const int p=13331;
int n;
void f()
{
    b[0]=1;
    for(int i=1;i<=n;i++)
    {
        b[i]=b[i-1]*p;
        h1[i]=h1[i-1]*p+s1[i]-'0';
        h2[i]=h2[i-1]*p+s2[i]-'0';
    }
}
ull gethash1(int l,int r)
{
    return h1[r]-h1[l-1]*b[r-l+1];
}
ull gethash2(int l,int r)
{
    return h2[r]-h2[l-1]*b[r-l+1];
}
bool check(int i,int mid)
{
    int l=i-mid+1,r=i+mid;
    return gethash1(l,r)==gethash2(n-r+1,n-l+1);
}
int main()
{
    scanf("%d%s",&n,s1+1);
    for(int i=1;i<=n;i++)
    {
        s2[n-i+1]=(1-(s1[i]-'0'))+'0';
    }
    f();
    long long ans=0;
    for(int i=1;i<n;i++)
    {
        int l=1,r=min(i,n-i),best=0;
        while(l<=r)
        {
            int mid=(l+r)/2;
            if(check(i,mid))
            {
                l=mid+1;
                best=mid;
            }
            else
            {
                r=mid-1;
            }
        }
        ans+=best;
    }
    printf("%lld",ans);
    return 0;
}
